import React from 'react';
import { motion } from 'framer-motion';

const Story = () => {
  return (
    <div className="pt-32 pb-24 px-6 overflow-hidden">
      <div className="max-w-4xl mx-auto text-center mb-20">
        <motion.p 
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          className="text-gold tracking-[0.4em] uppercase text-xs mb-4"
        >
          Established in Motion
        </motion.p>
        <motion.h1 
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          className="text-6xl font-cinzel font-bold mb-8"
        >
          Our Story
        </motion.h1>
      </div>

      <div className="max-w-7xl mx-auto grid md:grid-cols-2 gap-20 items-center mb-32">
        <motion.div
           initial={{ opacity: 0, x: -50 }}
           whileInView={{ opacity: 1, x: 0 }}
           viewport={{ once: true }}
        >
          <img 
            src="https://images.unsplash.com/photo-1504609773096-104ff2c73ba4?auto=format&fit=crop&w=800&q=80" 
            alt="Studio" 
            className="w-full grayscale hover:grayscale-0 transition-all duration-1000 border-l-4 border-gold p-2"
          />
        </motion.div>

        <motion.div
           initial={{ opacity: 0, x: 50 }}
           whileInView={{ opacity: 1, x: 0 }}
           viewport={{ once: true }}
           className="space-y-6"
        >
          <h2 className="text-3xl font-cinzel text-gold-gradient">The Dream Genesis</h2>
          <p className="text-ivory/70 leading-relaxed font-light first-letter:text-5xl first-letter:text-gold first-letter:font-cinzel first-letter:mr-3 first-letter:float-left">
            Dream of Dance (DOD) started with a single vision: to redefine dance education as a holistic artistic journey. What began as a small boutique studio has transformed into a prestigious hub for dancers of all ages.
          </p>
          <p className="text-ivory/70 leading-relaxed font-light">
            We believe that every soul has a unique rhythm. Our job is simply to provide the mirror and the technique to let that rhythm shine. Our studio is more than just four walls; it’s a living gallery of motion.
          </p>
          <div className="pt-6">
            <h4 className="font-cinzel text-gold text-lg">Curated Excellence</h4>
            <p className="text-sm font-light text-ivory/50">Our team consists of industry veterans and visionary artists.</p>
          </div>
        </motion.div>
      </div>
    </div>
  );
};

export default Story;
